const tooltipEl = document.querySelector('.chart-tooltip');

if (chartContainer && chartWrapper && tooltipEl) {
  const chart = createChart(chartContainer, {
    layout: {
      background: { color: 'transparent' },
      textColor: CHART_COLORS.textColor,
    },
    grid: {
      vertLines: { color: CHART_COLORS.gridLinesColor },
      horzLines: { color: CHART_COLORS.gridLinesColor },
    },
    crosshair: {
      vertLine: { color: CHART_COLORS.crosshairColor, width: 1, style: 0, labelVisible: false },
      horzLine: { color: CHART_COLORS.crosshairColor, width: 1, style: 0, labelVisible: false },
    },
    rightPriceScale: {
      borderVisible: false,
    },
    timeScale: {
      borderVisible: false,
      timeVisible: true,
      secondsVisible: false,
    },
    handleScroll: false,
    handleScale: false,
    autoSize: true,
  });

  const areaSeries = chart.addSeries(AreaSeries, {
    lineColor: CHART_COLORS.lineColor,
    topColor: CHART_COLORS.areaTopColor,
    bottomColor: CHART_COLORS.areaBottomColor,
    lineWidth: 2,
  });

  let hasReceivedData = false;
  let previousDataLength = 0;

  function toChartData(points) {
    return points.map((p) => ({
      time: Math.floor(p.time / 1000),
      value: p.value,
    }));
  }

  chartStore.subscribe((points) => {
    if (points.length === 0) return;

    if (!hasReceivedData) {
      hasReceivedData = true;
      areaSeries.setData(toChartData(points));
      chart.timeScale().fitContent();
      chartWrapper.removeAttribute('data-loading');
    } else if (points.length > previousDataLength) {
      const lastPoint = points[points.length - 1];
      areaSeries.update({
        time: Math.floor(lastPoint.time / 1000),
        value: lastPoint.value,
      });

